import { v4 as uuidv4 } from 'uuid';
import { differenceInDays, isPast, parseISO } from 'date-fns';

// ─── Priority logic ───────────────────────────────────────────────────────────
export function getPriority(dueDateStr) {
  if (!dueDateStr) return 'low';
  const due = parseISO(dueDateStr);
  const daysLeft = differenceInDays(due, new Date());
  if (daysLeft < 0)  return 'overdue';
  if (daysLeft <= 1) return 'urgent';
  if (daysLeft <= 3) return 'high';
  if (daysLeft <= 7) return 'medium';
  return 'low';
}

export function getDaysLeft(dueDateStr) {
  if (!dueDateStr) return null;
  const due = parseISO(dueDateStr);
  return differenceInDays(due, new Date());
}

export function getDaysLeftLabel(dueDateStr) {
  const days = getDaysLeft(dueDateStr);
  if (days === null) return '';
  if (days < 0)  return `Trễ ${Math.abs(days)} ngày`;
  if (days === 0) return 'Hôm nay!';
  if (days === 1) return 'Ngày mai';
  return `Còn ${days} ngày`;
}

export function getPriorityConfig(priority) {
  const configs = {
    overdue: { label: 'Quá hạn',   badge: 'badge-red',    color: 'var(--accent-red)',    icon: '❌' },
    urgent:  { label: 'Khẩn cấp',  badge: 'badge-red',    color: 'var(--accent-red)',    icon: '🔴' },
    high:    { label: 'Ưu tiên cao',badge: 'badge-yellow', color: 'var(--accent-yellow)', icon: '🟡' },
    medium:  { label: 'Trung bình', badge: 'badge-blue',   color: 'var(--accent-blue)',   icon: '🔵' },
    low:     { label: 'Thấp',       badge: 'badge-gray',   color: 'var(--text-muted)',    icon: '⚪' },
  };
  return configs[priority] || configs.low;
}

export function getStatusConfig(status) {
  const configs = {
    pending:     { label: 'Chưa hoàn thành', badge: 'badge-gray',   icon: '○' },
    in_progress: { label: 'Đang thực hiện',  badge: 'badge-blue',   icon: '◑' },
    completed:   { label: 'Đã hoàn thành',   badge: 'badge-green',  icon: '●' },
  };
  return configs[status] || configs.pending;
}

// ─── Sort tasks ───────────────────────────────────────────────────────────────
export function sortTasksByDueDate(tasks) {
  return [...tasks].sort((a, b) => {
    if (!a.dueDate && !b.dueDate) return 0;
    if (!a.dueDate) return 1;
    if (!b.dueDate) return -1;
    return new Date(a.dueDate) - new Date(b.dueDate);
  });
}

// ─── Default task steps ───────────────────────────────────────────────────────
export function generateDefaultSteps(taskName) {
  return [
    { id: uuidv4(), text: 'Đọc kỹ hướng dẫn bài tập', done: false },
    { id: uuidv4(), text: `Xem video/tài liệu liên quan đến "${taskName}"`, done: false },
    { id: uuidv4(), text: 'Lập dàn ý / phác thảo ý tưởng', done: false },
    { id: uuidv4(), text: 'Thực hiện nội dung chính', done: false },
    { id: uuidv4(), text: 'Kiểm tra định dạng và lỗi chính tả', done: false },
    { id: uuidv4(), text: 'Chuyển sang file PDF (nếu cần)', done: false },
    { id: uuidv4(), text: 'Nộp bài lên hệ thống', done: false },
  ];
}

// ─── Sample seed data ─────────────────────────────────────────────────────────
export function getSeedTasks() {
  const today = new Date();
  const fmt = (offset) => {
    const d = new Date(today);
    d.setDate(d.getDate() + offset);
    return d.toISOString().split('T')[0];
  };

  return [
    {
      id: uuidv4(),
      subject: 'Trí tuệ Nhân tạo',
      name: 'Xem video bài giảng chương 3',
      dueDate: fmt(1),
      instructions: 'Xem video bài giảng trên hệ thống LMS, ghi chú các khái niệm quan trọng.',
      status: 'in_progress',
      steps: generateDefaultSteps('Xem video bài giảng chương 3'),
      documents: [],
      notes: '',
      createdAt: new Date().toISOString(),
    },
    {
      id: uuidv4(),
      subject: 'Công nghệ Phần mềm',
      name: 'Thiết kế ca ứng dụng Open Claw',
      dueDate: fmt(2),
      instructions: 'Thiết kế một ca ứng dụng sử dụng Open Claw, viết báo cáo Word và nộp lên Moodle.',
      status: 'in_progress',
      steps: generateDefaultSteps('Thiết kế ca ứng dụng Open Claw'),
      documents: [],
      notes: 'Đã hoàn thành 60%',
      createdAt: new Date().toISOString(),
    },
    {
      id: uuidv4(),
      subject: 'Cơ sở Dữ liệu',
      name: 'Sắp xếp nội dung báo cáo ERD',
      dueDate: fmt(3),
      instructions: 'Vẽ sơ đồ ERD cho hệ thống quản lý thư viện, giải thích các quan hệ.',
      status: 'pending',
      steps: generateDefaultSteps('Sắp xếp nội dung báo cáo ERD'),
      documents: [],
      notes: '',
      createdAt: new Date().toISOString(),
    },
    {
      id: uuidv4(),
      subject: 'Mạng Máy tính',
      name: 'Kiểm tra định dạng Lab 5',
      dueDate: fmt(4),
      instructions: 'Hoàn thiện báo cáo Lab 5 về giao thức TCP/IP, nộp file PDF.',
      status: 'pending',
      steps: generateDefaultSteps('Kiểm tra định dạng Lab 5'),
      documents: [],
      notes: '',
      createdAt: new Date().toISOString(),
    },
    {
      id: uuidv4(),
      subject: 'Lập trình Web',
      name: 'Nộp đồ án cuối kỳ',
      dueDate: fmt(7),
      instructions: 'Nộp toàn bộ source code và báo cáo đồ án, demo trực tiếp với giảng viên.',
      status: 'pending',
      steps: generateDefaultSteps('Nộp đồ án cuối kỳ'),
      documents: [],
      notes: 'Cần hoàn thiện phần backend',
      createdAt: new Date().toISOString(),
    },
  ];
}
